  8→function extractClassFileHint(text) {
  9→  if (!text) return null;
 10→  const match = text.match(/(?:for|to|in|as)\s+([a-zA-Z0-9._-]+\.(?:xlsx|csv))/i);
 11→  return match ? match[1] : null;
 12→}
 13→
 14→function parseRuleBasedIntent(text) {
 15→  if (!text) return { intent: "unknown" };
 16→  const normalized = text.trim();
 17→
 18→  const summarizeMatch = normalized.match(
 19→    /(?:summarize|summary|analy[sz]e|overview|insights?|stats?).*(?:for|of|on|my)?\s*([a-zA-Z0-9._-]+\.(?:xlsx|csv))/i,
 20→  );
 21→  if (summarizeMatch) {
 22→    return { intent: "calculate_stats", classFile: summarizeMatch[1] };
 23→  }
 24→
 25→  const addMatch = normalized.match(/^add to\s+([^\s:]+)\s*:\s*(.+)$/i);
 26→  if (addMatch) {
 27→    return {
 28→      intent: "add_scores",
 29→      classFile: addMatch[1],
 30→      studentScores: parseStudentScorePairs(addMatch[2]),
 31→    };
 32→  }
 33→
 34→  const statsMatch = normalized.match(
 35→    /(?:calculate|compute).*(?:full\s+)?(?:stats|statistics|rankings).*(?:for|on)\s+([a-zA-Z0-9._-]+\.(?:xlsx|csv))/i,
 36→  );
 37→  if (statsMatch) {
 38→    return { intent: "calculate_stats", classFile: statsMatch[1] };
 39→  }
 40→
 41→  const reportMatch = normalized.match(
 42→    /generate.*(?:parent\s+)?(?:pdf\s+)?report.*for\s+([a-zA-Z0-9._-]+\.(?:xlsx|csv))/i,
 43→  );
 44→  if (reportMatch) {
 45→    return { intent: "generate_report", classFile: reportMatch[1] };
 46→  }
 47→
 48→  const curveMatch = normalized.match(
 49→    /apply\s+(gentle|bell|custom)?\s*curve\s+(?:to|for)\s+([a-zA-Z0-9._-]+\.(?:xlsx|csv))/i,
 50→  );
 51→  if (curveMatch) {
 52→    const modeHint = (curveMatch[1] || "gentle").toLowerCase();
 53→    const mode =
 54→      modeHint === "custom"
 55→        ? "custom_linear"
 56→        : modeHint === "bell"
 57→          ? "bell"
 58→          : "gentle_bell";
 59→    return { intent: "apply_curve", classFile: curveMatch[2], mode };
 60→  }
 61→
 62→  if (/backup all/i.test(normalized)) {
 63→    return { intent: "backup_all" };
 64→  }
 65→
 66→  const importMatch = normalized.match(
 67→    /(?:import|use)\s+(?:as\s+)?([a-zA-Z0-9._-]+\.(?:xlsx|csv))/i,
 68→  );
 69→  if (importMatch) {
 70→    return { intent: "import_document", classFile: importMatch[1] };
 71→  }
 72→
 73→  if (/^(help|menu|what can you do)\b/i.test(normalized)) {
 74→    return { intent: "help" };
 75→  }
 76→
 77→  if (/^(hi+|hey|hello|greetings|good\s*(morning|afternoon|evening)|yo|sup)\b/i.test(normalized)) {
 78→    return { intent: "help" };
 79→  }
 80→
 81→  return { intent: "unknown" };
 82→}
