 88→function parseJsonLoose(rawText) {
 89→  const text = stripThinkTags(String(rawText || "")).trim();
 90→  if (!text) return null;
 91→  try {
 92→    return JSON.parse(text);
 93→  } catch {
 94→    const firstBrace = text.indexOf("{");
 95→    const lastBrace = text.lastIndexOf("}");
 96→    if (firstBrace >= 0 && lastBrace > firstBrace) {
 97→      try {
 98→        return JSON.parse(text.slice(firstBrace, lastBrace + 1));
 99→      } catch {
100→        return null;
101→      }
102→    }
103→    return null;
104→  }
105→}
