129→  async inferIntentWithOllama(userId, text) {
130→    const memory = await this.gradeService.readUserMemory(userId);
131→    const historySnippet = (memory.history || [])
132→      .slice(-6)
133→      .map((item) => `${item.role}: ${item.text}`)
134→      .join("\n");
135→
136→    const extractionPrompt = [
137→      "/no_think",
138→      "Extract teacher intent from the message.",
139→      "Return strict JSON ONLY, no explanation.",
140→      '{ "intent": "add_scores|calculate_stats|generate_report|apply_curve|backup_all|import_document|help|unknown", "classFile": "optional", "studentScores":[{"student":"Name","score":90}], "mode":"optional" }',
141→      "Rules:",
142→      "- Do not invent student scores.",
143→      "- Keep classFile null if not provided.",
144→      "- studentScores must be empty unless clearly provided.",
145→      "- Reply with ONLY the JSON object, nothing else.",
146→      "",
147→      "Recent conversation:",
148→      historySnippet || "(none)",
149→      "",
150→      `Current message: ${text}`,
151→    ].join("\n");
152→
153→    const doRequest = async () => {
154→      const response = await postOllamaChat({
155→        baseUrl: this.config.ollama.baseUrl,
156→        model: this.config.ollama.model,
157→        messages: [
158→          { role: "system", content: SYSTEM_PROMPT },
159→          { role: "user", content: extractionPrompt },
160→        ],
161→        timeoutMs: this.config.ollama.requestTimeoutMs,
162→        logger: this.logger,
163→        stream: false,
164→      });
165→      return response?.data?.message?.content;
166→    };
167→
168→    const content = await pRetry(doRequest, {
169→      retries: Math.max(0, (this.config.ollama.retries || 1) - 1),
170→      factor: 2,
171→      minTimeout: 600,
172→      maxTimeout: 5000,
173→      onFailedAttempt: (error) => {
174→        this.logger.warn(`Intent extraction retry ${error.attemptNumber}: ${error.message}`);
175→      },
176→    });
177→
178→    return parseJsonLoose(content) || { intent: "unknown" };
179→  }
