189→    try {
190→      const ollamaIntent = await this.inferIntentWithOllama(userId, text);
191→      return {
192→        intent: ollamaIntent.intent || "unknown",
193→        classFile: ollamaIntent.classFile || null,
194→        studentScores: Array.isArray(ollamaIntent.studentScores)
195→          ? ollamaIntent.studentScores
196→          : [],
197→        mode: ollamaIntent.mode || null,
198→      };
199→    } catch (error) {
