534→          `Backup: ${backup.backupPath}`,
535→          `Rows written: ${(pending.payload?.rows || []).length}`,
536→        ].join("\n");
537→      } else if (pending.type === "generate_report") {
538→        const backup = await createBackup(pending.targetFile, this.config.paths.backups);
539→        backupPath = backup.backupPath;
540→        const result = await this.pythonBridge.runPython("generate_report.py", {
541→          rows: pending.payload?.rows || [],
542→          classFile: pending.payload?.classFile,
