import fs from "fs/promises";
import path from "path";
import { v4 as uuidv4 } from "uuid";
import { writeAudit } from "../logger.js";
import {
  createBackup,
  detectOutliers,
  isoNow,
  normalizeUserId,
  summarizeRowsForPreview,
  validateScore,
  compactTimestamp,
} from "../tools/common.js";

export class GradeService {
  constructor({ config, logger, excelTool, pythonBridge }) {
    this.config = config;
    this.logger = logger;
    this.excelTool = excelTool;
    this.pythonBridge = pythonBridge;
  }

  memoryFilePath(userId) {
    return path.join(this.config.paths.memory, `${normalizeUserId(userId)}.json`);
  }

  async readUserMemory(userId) {
    const memoryPath = this.memoryFilePath(userId);
    try {
      const raw = await fs.readFile(memoryPath, "utf8");
      const parsed = JSON.parse(raw);
      return {
        userId,
        lastUsedClassFile: parsed.lastUsedClassFile || null,
        lastUploadedDocument: parsed.lastUploadedDocument || null,
        pendingAction: parsed.pendingAction || null,
        recentActions: Array.isArray(parsed.recentActions)
          ? parsed.recentActions
          : [],
        history: Array.isArray(parsed.history) ? parsed.history : [],
      };
    } catch {
      return {
        userId,
        lastUsedClassFile: null,
        lastUploadedDocument: null,
        pendingAction: null,
        recentActions: [],
        history: [],
      };
    }
  }

  async writeUserMemory(userId, memory) {
    const memoryPath = this.memoryFilePath(userId);
    await fs.writeFile(memoryPath, JSON.stringify(memory, null, 2), "utf8");
  }

  async addConversation(userId, role, text) {
    if (!text) return;
    const memory = await this.readUserMemory(userId);
    const item = {
      role,
      text: String(text).slice(0, 1200),
      at: isoNow(),
    };
    memory.history = [...memory.history, item].slice(
      -this.config.limits.maxConversationItems,
    );
    await this.writeUserMemory(userId, memory);
  }

  async setLastUsedClass(userId, classFile) {
    const memory = await this.readUserMemory(userId);
    memory.lastUsedClassFile = classFile;
    await this.writeUserMemory(userId, memory);
  }

  async setLastUploadedDocument(userId, documentInfo) {
    const memory = await this.readUserMemory(userId);
    memory.lastUploadedDocument = documentInfo || null;
    await this.writeUserMemory(userId, memory);
  }

  async getLastUploadedDocument(userId) {
    const memory = await this.readUserMemory(userId);
    return memory.lastUploadedDocument || null;
  }

  async setPendingAction(userId, action) {
    const memory = await this.readUserMemory(userId);
    memory.pendingAction = action;
    memory.recentActions = [
      {
        id: action.actionId,
        type: action.type,
        target: action.targetFile || action.target,
        at: isoNow(),
      },
      ...memory.recentActions,
    ].slice(0, 30);
    await this.writeUserMemory(userId, memory);
  }

  async clearPendingAction(userId) {
    const memory = await this.readUserMemory(userId);
    memory.pendingAction = null;
    await this.writeUserMemory(userId, memory);
  }

  async getPendingAction(userId) {
    const memory = await this.readUserMemory(userId);
    return memory.pendingAction;
  }

  resolveClassFile(memory, requestedClassFile) {
    const candidate =
      requestedClassFile || memory.lastUsedClassFile || "class1.xlsx";
    const filePath = this.excelTool.resolveGradeFile(candidate);
    return { classFile: path.basename(filePath), filePath };
  }

  async prepareAddScores(context, args) {
    const userId = context.userId;
    const memory = await this.readUserMemory(userId);
    const { classFile, filePath } = this.resolveClassFile(memory, args.classFile);
    const updates = Array.isArray(args.studentScores) ? args.studentScores : [];

    if (updates.length === 0) {
      return {
        replyText:
          "I could not find any student scores to add. Please send in this format: Add to math.xlsx: Alice 94, Bob 87",
      };
    }

    const invalid = updates.filter(
      (entry) =>
        !entry?.student ||
        !validateScore(
          entry.score,
          this.config.limits.minScore,
          this.config.limits.maxScore,
        ),
    );
    if (invalid.length) {
      return {
        replyText:
          "Some scores are invalid. Please ensure each score is numeric and between 0 and 100.",
      };
    }

    const readResult = await this.excelTool.readGradeFile(filePath);
    const schema = this.excelTool.detectSchema(readResult.rows);
    const processResult = await this.pythonBridge.runPython("process_grades.py", {
      operation: "update_scores",
      rows: readResult.rows,
      updates,
      studentColumn: schema.studentColumn,
      scoreColumn: args.scoreColumn || "Score",
    });

    if (!processResult.ok) {
      return {
        replyText: `I could not process those scores: ${processResult.error?.message || "Unknown error."}`,
      };
    }

    const data = processResult.data || {};
    const rows = Array.isArray(data.rows) ? data.rows : [];
    const summary = data.summary || {};
    const warnings = Array.isArray(data.warnings) ? data.warnings : [];
    const numericValues = rows
      .map((row) => row.FinalScore)
      .filter((value) => Number.isFinite(Number(value)));
    const outliers = detectOutliers(numericValues);
    if (outliers.length) {
      warnings.push(
        `Outlier warning: ${outliers.length} score(s) are statistically unusual.`,
      );
    }

    const action = {
      actionId: uuidv4(),
      type: "save_grades",
      userId,
      targetFile: filePath,
      payload: {
        rows,
        classFile,
        source: args.source || "text",
      },
      createdAt: isoNow(),
      preview: {
        updateCount: updates.length,
        rowCount: rows.length,
        summary,
        warnings,
      },
    };
    await this.setPendingAction(userId, action);

    const preview = summarizeRowsForPreview(rows, 6);
    const warningText = warnings.length
      ? `\nWarnings:\n- ${warnings.join("\n- ")}`
      : "";

    return {
      replyText: [
        `Prepared updates for ${classFile}.`,
        `Students in file after update: ${rows.length}.`,
        `Class mean: ${Number(summary.mean || 0).toFixed(2)} | Median: ${Number(summary.median || 0).toFixed(2)} | Std: ${Number(summary.std || 0).toFixed(2)}`,
        "Preview:",
        preview,
        warningText,
        `Save to ${classFile}? Reply yes or no.`,
      ]
        .filter(Boolean)
        .join("\n"),
      pendingConfirmation: {
        actionId: action.actionId,
        prompt: `Save to ${classFile}?`,
      },
    };
  }

  async calculateStats(context, args) {
    const userId = context.userId;
    const memory = await this.readUserMemory(userId);
    const { classFile, filePath } = this.resolveClassFile(memory, args.classFile);

    const readResult = await this.excelTool.readGradeFile(filePath);
    if (!readResult.fileExists || readResult.rows.length === 0) {
      return {
        replyText: `I could not find grade rows in ${classFile}. Please send data first.`,
      };
    }

    const result = await this.pythonBridge.runPython("process_grades.py", {
      operation: "compute_stats",
      rows: readResult.rows,
      studentColumn: args.studentColumn || null,
      scoreColumn: args.scoreColumn || null,
    });

    if (!result.ok) {
      return {
        replyText: `I could not calculate statistics: ${result.error?.message || "Unknown error."}`,
      };
    }

    const data = result.data || {};
    const summary = data.summary || {};
    const rankings = Array.isArray(data.rankings) ? data.rankings : [];
    const topRanks = rankings.slice(0, 10);

    const rankingLines = topRanks.length
      ? topRanks
          .map(
            (item) =>
              `${item.rank}. ${item.student} - ${Number(item.score).toFixed(2)}`,
          )
          .join("\n")
      : "No rankings available.";

    await this.setLastUsedClass(userId, classFile);
    writeAudit({
      timestamp: isoNow(),
      userId,
      action: "calculate_stats",
      status: "success",
      target: classFile,
      details: {
        rows: readResult.rows.length,
      },
    });

    return {
      replyText: [
        `Statistics for ${classFile}:`,
        `Mean: ${Number(summary.mean || 0).toFixed(2)}`,
        `Median: ${Number(summary.median || 0).toFixed(2)}`,
        `Std Dev: ${Number(summary.std || 0).toFixed(2)}`,
        `P25: ${Number(summary.p25 || 0).toFixed(2)} | P75: ${Number(summary.p75 || 0).toFixed(2)} | P90: ${Number(summary.p90 || 0).toFixed(2)}`,
        "Top Rankings:",
        rankingLines,
      ].join("\n"),
    };
  }

  async prepareGenerateReport(context, args) {
    const userId = context.userId;
    const memory = await this.readUserMemory(userId);
    const { classFile, filePath } = this.resolveClassFile(memory, args.classFile);
    const readResult = await this.excelTool.readGradeFile(filePath);

    if (!readResult.fileExists || readResult.rows.length === 0) {
      return {
        replyText: `I could not generate a report because ${classFile} has no grade rows.`,
      };
    }

    const reportName = `${path.parse(classFile).name}_report_${compactTimestamp()}.pdf`;
    const reportPath = path.join(this.config.paths.reports, reportName);

    const action = {
      actionId: uuidv4(),
      type: "generate_report",
      userId,
      targetFile: reportPath,
      payload: {
        classFile,
        sourcePath: filePath,
        reportPath,
        rows: readResult.rows,
      },
      createdAt: isoNow(),
      preview: {
        rowCount: readResult.rows.length,
      },
    };
    await this.setPendingAction(userId, action);

    return {
      replyText: [
        `Prepared parent report for ${classFile}.`,
        `Output file: ${path.basename(reportPath)}`,
        "Generate this PDF now? Reply yes or no.",
      ].join("\n"),
      pendingConfirmation: {
        actionId: action.actionId,
        prompt: `Generate report for ${classFile}?`,
      },
    };
  }

  async prepareApplyCurve(context, args) {
    const userId = context.userId;
    const memory = await this.readUserMemory(userId);
    const { classFile, filePath } = this.resolveClassFile(memory, args.classFile);
    const readResult = await this.excelTool.readGradeFile(filePath);

    if (!readResult.fileExists || readResult.rows.length === 0) {
      return {
        replyText: `I could not apply a curve because ${classFile} has no grade rows.`,
      };
    }

    const curveResult = await this.pythonBridge.runPython("apply_curve.py", {
      mode: args.mode || "gentle_bell",
      rows: readResult.rows,
      minScore: this.config.limits.minScore,
      maxScore: this.config.limits.maxScore,
      custom: args.custom || null,
    });

    if (!curveResult.ok) {
      return {
        replyText: `I could not apply a curve: ${curveResult.error?.message || "Unknown error."}`,
      };
    }

    const data = curveResult.data || {};
    const curvedRows = Array.isArray(data.rows) ? data.rows : [];
    const summary = data.summary || {};
    const warnings = Array.isArray(data.warnings) ? data.warnings : [];

    const action = {
      actionId: uuidv4(),
      type: "save_grades",
      userId,
      targetFile: filePath,
      payload: {
        rows: curvedRows,
        classFile,
        source: "curve",
      },
      createdAt: isoNow(),
      preview: {
        rowCount: curvedRows.length,
        summary,
        warnings,
      },
    };
    await this.setPendingAction(userId, action);

    const preview = summarizeRowsForPreview(curvedRows, 6);
    const warningText = warnings.length
      ? `\nWarnings:\n- ${warnings.join("\n- ")}`
      : "";

    return {
      replyText: [
        `Prepared curved scores for ${classFile}.`,
        `Before mean: ${Number(summary.beforeMean || 0).toFixed(2)} | After mean: ${Number(summary.afterMean || 0).toFixed(2)}`,
        "Preview:",
        preview,
        warningText,
        `Save curved results to ${classFile}? Reply yes or no.`,
      ]
        .filter(Boolean)
        .join("\n"),
      pendingConfirmation: {
        actionId: action.actionId,
        prompt: `Save curved results to ${classFile}?`,
      },
    };
  }

  async prepareBackupAll(context) {
    const userId = context.userId;
    const files = await this.excelTool.listGradeFiles();
    if (!files.length) {
      return {
        replyText: "No grade files were found in data/grades to back up.",
      };
    }

    const action = {
      actionId: uuidv4(),
      type: "backup_all",
      userId,
      target: "data/grades",
      createdAt: isoNow(),
      payload: {
        files,
      },
      preview: {
        fileCount: files.length,
      },
    };
    await this.setPendingAction(userId, action);

    return {
      replyText: `Prepared backup for ${files.length} grade file(s). Proceed? Reply yes or no.`,
      pendingConfirmation: {
        actionId: action.actionId,
        prompt: "Backup all files?",
      },
    };
  }

  async preparePhotoSave(context, args) {
    const rows = Array.isArray(args.rows) ? args.rows : [];
    if (!rows.length) {
      return {
        replyText:
          "I could not extract valid score rows from the photo. Please try a clearer image.",
      };
    }
    return this.prepareAddScores(context, {
      classFile: args.classFile,
      studentScores: rows,
      source: "photo",
    });
  }

  async prepareDocumentImport(context, args) {
    const userId = context.userId;
    if (!args.documentPath) {
      return { replyText: "No document path was provided for import." };
    }

    const fileName = args.classFile || args.originalName || "imported_class.xlsx";
    const targetPath = this.excelTool.resolveGradeFile(fileName);

    const action = {
      actionId: uuidv4(),
      type: "import_document",
      userId,
      targetFile: targetPath,
      createdAt: isoNow(),
      payload: {
        sourcePath: args.documentPath,
        targetPath,
      },
      preview: {
        sourcePath: args.documentPath,
        targetPath,
      },
    };
    await this.setPendingAction(userId, action);
    return {
      replyText: `I received ${path.basename(args.documentPath)}. Import it as ${path.basename(targetPath)}? Reply yes or no.`,
      pendingConfirmation: {
        actionId: action.actionId,
        prompt: "Import uploaded file?",
      },
    };
  }

  async handleConfirmation(context, decision) {
    const userId = context.userId;
    const pending = await this.getPendingAction(userId);
    if (!pending) {
      return {
        replyText: "There is no pending action to confirm right now.",
      };
    }

    if (decision === "no") {
      await this.clearPendingAction(userId);
      writeAudit({
        timestamp: isoNow(),
        userId,
        action: pending.type,
        status: "cancelled",
        target: pending.targetFile || pending.target || "n/a",
      });
      return {
        replyText: "Cancelled. No files were changed.",
      };
    }

    if (decision !== "yes") {
      return {
        replyText: "Please reply with yes or no.",
      };
    }

    try {
      let replyText = "Action completed successfully.";
      let backupPath = null;

      if (pending.type === "save_grades") {
        const backup = await createBackup(pending.targetFile, this.config.paths.backups);
        backupPath = backup.backupPath;
        await this.excelTool.writeGradeFile(
          pending.targetFile,
          pending.payload?.rows || [],
        );
        await this.setLastUsedClass(userId, path.basename(pending.targetFile));
        replyText = [
          `Saved ${path.basename(pending.targetFile)} successfully.`,
          `Backup: ${backup.backupPath}`,
          `Rows written: ${(pending.payload?.rows || []).length}`,
        ].join("\n");
      } else if (pending.type === "generate_report") {
        const backup = await createBackup(pending.targetFile, this.config.paths.backups);
        backupPath = backup.backupPath;
        const result = await this.pythonBridge.runPython("generate_report.py", {
          rows: pending.payload?.rows || [],
          classFile: pending.payload?.classFile,
          outputPath: pending.payload?.reportPath,
        });
        if (!result.ok) {
          throw new Error(result.error?.message || "Report generation failed.");
        }
        replyText = [
          `Generated report for ${pending.payload?.classFile}.`,
          `PDF: ${result.data?.reportPath || pending.payload?.reportPath}`,
          `Backup marker: ${backup.backupPath}`,
        ].join("\n");
      } else if (pending.type === "backup_all") {
        const files = pending.payload?.files || [];
        const backups = [];
        for (const fileName of files) {
          const sourcePath = this.excelTool.resolveGradeFile(fileName);
          const backup = await createBackup(sourcePath, this.config.paths.backups);
          backups.push(backup.backupPath);
        }
        replyText = `Backup complete. ${backups.length} file(s) copied into data/backups.`;
      } else if (pending.type === "import_document") {
        const targetPath = pending.payload?.targetPath;
        const sourcePath = pending.payload?.sourcePath;
        const backup = await createBackup(targetPath, this.config.paths.backups);
        backupPath = backup.backupPath;
        await fs.copyFile(sourcePath, targetPath);
        await this.setLastUsedClass(userId, path.basename(targetPath));
        replyText = [
          `Imported file to ${path.basename(targetPath)}.`,
          `Backup: ${backup.backupPath}`,
        ].join("\n");
      } else {
        throw new Error(`Unsupported pending action: ${pending.type}`);
      }

      await this.clearPendingAction(userId);
      writeAudit({
        timestamp: isoNow(),
        userId,
        action: pending.type,
        status: "success",
        target: pending.targetFile || pending.target || "n/a",
        backupPath,
        details: pending.preview || {},
      });
      return { replyText };
    } catch (error) {
      this.logger.error(`Failed to execute pending action: ${error.message}`);
      writeAudit({
        timestamp: isoNow(),
        userId,
        action: pending.type,
        status: "failure",
        target: pending.targetFile || pending.target || "n/a",
        details: { error: error.message },
      });
      return {
        replyText:
          "I encountered an error while executing the action. No further changes were made. Please try again.",
      };
    }
  }
}

